mapper.select:
SELECT COUNT(*)
FROM production_line
WHERE status = #{status}

mapper.update:
UPDATE production_line
SET status = #{status}
WHERE line_id = #{lineId}

UPDATE production_line
SET `status` = #{status}, updated_at = NOW()
WHERE line_id = #{lineId}
  AND NOT EXISTS (
    SELECT 1
    FROM work_order wo
    WHERE wo.line_id = #{lineId}
      AND wo.status = 'IN_PROGRESS'
      AND wo.is_deleted = FALSE
  )
